M = DATA.map &:chomp
Y, X = M.size, M[0].size
YY, XX = 0...Y, 0...X
N = [[-1, 0], [0, -1], [0, 1], [1, 0]]

M.each_with_index { |l, y|
  l.each_char.with_index { |c, x|
    S = [y, x] if c[?S]
  }
}

def steps(start, distances, wrap: false)
  q = [start]
  s = Set.new
  r = Array.new(distances.max + 1, 0)

  (1..distances.max).each { |d|
    q = q.flat_map { |y, x|
      N.filter_map { |dy, dx|
        n = ny = y + dy, nx = x + dx
        s.add?(n) && (wrap ? !M[ny % Y][nx % X][?#] : YY === ny && XX === nx && !M[ny][nx][?#]) && n
      }
    }
    r[d] = q.size + r[d - 2]
  }

  distances.map { r[_1] }
end

p steps(S, [64])[0]

t, x0 = 26_501_365.divmod(X)
x1 = x0 + X
x2 = x1 + X

y0, y1, y2 = steps(S, [x0, x1, x2], wrap: true)

v = y1 - y0
a = y2 - 2 * y1 + y0

p y0 + v * t + a * t * (t - 1) / 2

__END__
